# --- plot helper (hidden) — the register timeline, driven by run_trace --------
# Asks the student's run_trace for a snapshot of all 4 registers after each step,
# then draws one step-line per register. Falls back to a plain-Python trace so
# the panel always animates, even before run_trace is finished.
def __ref_exec(regs, instr):
    op = (instr >> 6) & 3
    dest = (instr >> 4) & 3
    a = (instr >> 2) & 3
    b = instr & 3
    x, y = regs[a], regs[b]
    if op == 0:
        r = (x + y) & 0xF
    elif op == 1:
        r = (x - y) & 0xF
    elif op == 2:
        r = x & y
    else:
        r = x | y
    out = list(regs)
    out[dest] = r
    return out

def __ref_trace(program, regs):
    t = [list(regs)]
    for instr in program:
        regs = __ref_exec(regs, instr)
        t.append(list(regs))
    return t

def __valid(trace, n):
    if not isinstance(trace, list) or len(trace) != n + 1:
        return False
    for snap in trace:
        if not isinstance(snap, list) or len(snap) != 4:
            return False
    return True

def __steps(vals):
    pts = []
    for t, v in enumerate(vals):
        pts.append([t, v])
        pts.append([t + 1, v])
    return pts

def __plot(program, regs):
    n = len(program)
    trace = __ref_trace(program, regs)
    rt = globals().get("run_trace")
    if rt is not None:
        try:
            got = rt(program, regs)
            if __valid(got, n):
                trace = got
        except Exception:
            pass
    series = []
    for r in range(4):
        vals = [snap[r] for snap in trace]
        series.append({"name": "R" + str(r), "points": __steps(vals), "highlight": (r == 0)})
    return series
